import { useEffect } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import { Link } from 'react-router-dom'
import { getCompanies } from '../store/slices/companySlice'
import { 
  Users, Building2, Package, HardHat, DollarSign, FileText, BarChart3, 
  Bell, Truck 
} from 'lucide-react'
import {
  ResponsiveContainer,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend
} from 'recharts'

const Dashboard = () => {
  const dispatch = useDispatch()
  const { user } = useSelector((state) => state.auth)
  const { companies, currentCompany } = useSelector((state) => state.company)

  useEffect(() => {
    dispatch(getCompanies())
  }, [dispatch])

  const stats = [
    { label: 'Total Employees', value: '124', icon: Users, color: 'bg-blue-500', href: '/employees' },
    { label: 'Active Projects', value: '12', icon: HardHat, color: 'bg-green-500', href: '/projects' },
    { label: 'Total Revenue', value: '$2.4M', icon: DollarSign, color: 'bg-yellow-500', href: '/invoices' },
    { label: 'Pending Invoices', value: '28', icon: FileText, color: 'bg-purple-500', href: '/invoices' },
    { label: 'Stock Items', value: '1,245', icon: Package, color: 'bg-indigo-500', href: '/products' },
    { label: 'Notifications', value: '3', icon: Bell, color: 'bg-orange-500', href: '/notifications' },
  ]

  const chartData = [
    { month: 'Jan', revenue: 4000, expenses: 2400 },
    { month: 'Feb', revenue: 3000, expenses: 1398 },
    { month: 'Mar', revenue: 2000, expenses: 9800 },
    { month: 'Apr', revenue: 2780, expenses: 3908 },
    { month: 'May', revenue: 1890, expenses: 4800 },
    { month: 'Jun', revenue: 2390, expenses: 3800 },
  ]

  const recentActivities = [
    { id: 1, action: 'New employee added', module: 'HR', time: '2 hours ago', href: '/employees' },
    { id: 2, action: 'Project "Tower A" updated', module: 'Projects', time: '4 hours ago', href: '/projects' },
    { id: 3, action: 'Invoice #1234 created', module: 'Finance', time: '5 hours ago', href: '/invoices' },
    { id: 4, action: 'New purchase order created', module: 'Inventory', time: '1 day ago', href: '/products' },
  ]

  return (
    <div className="p-6 space-y-8">
      {/* Header */}
      <div>
        <h1 className="text-3xl font-bold text-gray-900">
          Welcome back, {user?.name || 'User'}
        </h1>
        <p className="text-xl text-gray-600 mt-1">
          {currentCompany ? currentCompany.name : 'Select a company to get started'}
        </p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {stats.map((stat, index) => (
          <Link key={index} to={stat.href} className="group">
            <div className="bg-white hover:shadow-lg transition-all duration-200 rounded-2xl p-6 border border-gray-100 hover:border-gray-200">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">{stat.label}</p>
                  <p className="text-3xl font-bold text-gray-900 mt-1 group-hover:text-blue-600 transition-colors">{stat.value}</p>
                </div>
                <div className={`${stat.color} p-3 rounded-xl shadow-lg group-hover:scale-110 transition-transform`}>
                  <stat.icon className="text-white" size={24} />
                </div>
              </div>
            </div>
          </Link>
        ))}
      </div>

      {/* Charts & Activities */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Revenue Chart */}
        <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
          <div className="flex items-center gap-3 mb-6">
            <BarChart3 size={28} className="text-blue-600" />
            <h2 className="text-2xl font-bold text-gray-900">Revenue Overview</h2>
          </div>
          <ResponsiveContainer width="100%" height={350}>
            <BarChart data={chartData} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
              <CartesianGrid vertical={false} strokeDasharray="3 3" stroke="#f1f5f9" />
              <XAxis dataKey="month" fontSize={14} tickLine={false} axisLine={false} />
              <YAxis tickLine={false} axisLine={false} fontSize={12} />
              <Tooltip />
              <Legend />
              <Bar dataKey="revenue" fill="#3B82F6" radius={[4, 4, 0, 0]} />
              <Bar dataKey="expenses" fill="#EF4444" radius={[4, 4, 0, 0]} />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Recent Activities */}
        <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Recent Activities</h2>
          <div className="space-y-4">
            {recentActivities.map((activity) => (
              <Link key={activity.id} to={activity.href} className="block hover:bg-gray-50 p-4 rounded-xl transition-colors">
                <div className="flex items-start space-x-3">
                  <div className="w-2 h-2 bg-blue-500 rounded-full mt-2 flex-shrink-0"></div>
                  <div className="flex-1 min-w-0">
                    <p className="text-gray-900 font-medium truncate">{activity.action}</p>
                    <p className="text-sm text-gray-500">{activity.module} • {activity.time}</p>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        </div>
      </div>

      {/* Quick Actions */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { title: 'Add Employee', desc: 'Register new team member', href: '/employees/new', bg: 'from-blue-500 to-blue-600' },
          { title: 'New Project', desc: 'Start construction project', href: '/projects/new', bg: 'from-green-500 to-green-600' },
          { title: 'Create Invoice', desc: 'Generate billing invoice', href: '/invoices/new', bg: 'from-purple-500 to-purple-600' },
        ].map((action, index) => (
          <Link key={index} to={action.href} className="group">
            <div className={`bg-gradient-to-br ${action.bg} hover:from-opacity-90 rounded-2xl p-8 text-white shadow-lg hover:shadow-2xl transition-all duration-300 hover:-translate-y-1`}>
              <h3 className="text-2xl font-bold mb-3 group-hover:scale-105 transition-transform">{action.title}</h3>
              <p className="opacity-90">{action.desc}</p>
              <div className="mt-6 flex items-center gap-2 opacity-90 group-hover:opacity-100">
                <span>Go Now</span>
                <svg className="w-4 h-4 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
                </svg>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </div>
  )
}

export default Dashboard

