import { useState } from 'react'
import { Link, useLocation, Outlet } from 'react-router-dom'
import { useSelector, useDispatch } from 'react-redux'
import { logout } from '../../store/slices/authSlice'
import { 
  LayoutDashboard, Building2, Users, Package, HardHat, 
  Wrench, Globe, Hotel, Truck, Home, DollarSign, Building, 
  Menu, X, ChevronDown
} from 'lucide-react'

const MainLayout = () => {
  const [sidebarOpen, setSidebarOpen] = useState(false)
  const [companyDropdown, setCompanyDropdown] = useState(false)
  const location = useLocation()
  const dispatch = useDispatch()
  const { user } = useSelector((state) => state.auth)
  const { currentCompany } = useSelector((state) => state.company)

  const menuItems = [
    { path: '/', label: 'Dashboard', icon: LayoutDashboard },
    { path: '/companies', label: 'Companies', icon: Building2 },
    { path: '/employees', label: 'HR', icon: Users },
    { path: '/departments', label: 'Departments', icon: Building },
    { path: '/customers', label: 'Customers', icon: Users },
    { path: '/suppliers', label: 'Suppliers', icon: Truck },
    { path: '/warehouses', label: 'Warehouses', icon: Home },
    { path: '/products', label: 'Products', icon: Package },
    { path: '/invoices', label: 'Finance', icon: DollarSign },
    { path: '/projects', label: 'Projects', icon: HardHat },
    { path: '/work-orders', label: 'E-Mechanical', icon: Wrench },
    { path: '/shipments', label: 'Import/Export', icon: Globe },
    { path: '/properties', label: 'Real Estate', icon: Hotel },
  ]

  const isActive = (path) => location.pathname === path || (path !== '/' && location.pathname.startsWith(path))

  return (
    <div className="h-screen flex bg-gray-50">
      {/* Sidebar */}
      <div className="hidden lg:block lg:w-72 bg-gray-900 flex-shrink-0">
        <div className="h-full flex flex-col">
          <div className="flex items-center justify-between p-6 border-b border-gray-700">
            <h1 className="text-xl font-bold text-white">TSEMEX ERP</h1>
          </div>
          
          <nav className="flex-1 px-6 py-4 overflow-y-auto space-y-2">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`flex items-center px-4 py-3 rounded-lg text-gray-200 hover:bg-gray-800 hover:text-white transition-colors ${
                  isActive(item.path) 
                    ? 'bg-blue-600 text-white border-l-4 border-blue-400' 
                    : ''
                }`}
              >
                <item.icon className="w-5 h-5 mr-3" />
                <span>{item.label}</span>
              </Link>
            ))}
          </nav>
          
          <div className="p-6 border-t border-gray-700">
            <button 
              onClick={() => dispatch(logout())}
              className="w-full bg-red-600 hover:bg-red-700 text-white font-medium py-2 px-4 rounded-lg transition-colors"
            >
              Logout
            </button>
          </div>
        </div>
      </div>

      {/* Main content */}
      <div className="flex flex-col flex-1 overflow-hidden lg:ml-72">
        {/* Header */}
        <header className="bg-white shadow-sm border-b border-gray-200 px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <button className="lg:hidden p-2 rounded-md text-gray-500 hover:text-gray-900 hover:bg-gray-100">
                <Menu className="h-6 w-6" />
              </button>
              <h1 className="text-2xl font-bold text-gray-900">
                {menuItems.find(item => isActive(item.path))?.label || 'Dashboard'}
              </h1>
            </div>

            <div className="flex items-center space-x-4">
              <div className="relative">
                <button
                  onClick={() => setCompanyDropdown(!companyDropdown)}
                  className="flex items-center space-x-2 px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                >
                  <Building2 className="h-4 w-4" />
                  <span>{currentCompany?.name || 'Select Company'}</span>
                  <ChevronDown className="h-4 w-4" />
                </button>
                {companyDropdown && (
                  <div className="absolute right-0 mt-2 w-56 bg-white rounded-md shadow-lg ring-1 ring-black ring-opacity-5 py-1 z-50">
                    <Link to="/companies" className="block px-4 py-2 text-sm text-gray-700 hover:bg-gray-100 rounded-md">
                      Manage Companies
                    </Link>
                  </div>
                )}
              </div>

              <div className="flex items-center space-x-2">
                <div className="w-8 h-8 bg-blue-600 text-white rounded-full flex items-center justify-center text-sm font-semibold">
                  {user?.name?.[0] || 'U'}
                </div>
                <span className="text-sm font-medium text-gray-900">{user?.name || 'User'}</span>
              </div>
            </div>
          </div>
        </header>

        {/* Content area */}
        <main className="flex-1 overflow-y-auto p-0">
          <Outlet />
        </main>
      </div>
    </div>
  )
}

export default MainLayout

